import { Calendar, Clock, User } from "lucide-react";
import type { Article } from "../../types";

export interface BlogCardProps {
  article: Article;
  basePath?: string;
}

export function BlogCard({ article, basePath = "/blog" }: BlogCardProps) {
  const articleUrl = `${basePath}/${article.slug}`;

  const formattedDate = article.published_at
    ? new Date(article.published_at).toLocaleDateString("nl-NL", {
        year: "numeric",
        month: "long",
        day: "numeric",
      })
    : null;

  return (
    <article className="group flex flex-col overflow-hidden rounded-lg border border-border bg-secondary shadow-sm transition-shadow hover:shadow-md">
      {/* Image */}
      <a href={articleUrl} className="relative block aspect-[16/9] overflow-hidden">
        {article.featured_image ? (
          <img
            src={article.featured_image}
            alt={article.title}
            className="h-full w-full object-cover transition-transform duration-300 group-hover:scale-105"
          />
        ) : (
          <div className="h-full w-full bg-gradient-to-br from-primary/20 to-primary/5" />
        )}

        {/* Category badge */}
        {article.category && (
          <span className="absolute left-3 top-3 rounded-full bg-primary px-3 py-1 text-xs font-medium text-primary-foreground">
            {article.category.name}
          </span>
        )}
      </a>

      {/* Content */}
      <div className="flex flex-1 flex-col p-4 sm:p-5">
        <h3 className="mb-2 text-lg font-semibold leading-snug text-foreground transition-colors group-hover:text-primary">
          <a href={articleUrl}>{article.title}</a>
        </h3>

        {article.excerpt && (
          <p className="mb-4 line-clamp-2 text-sm leading-relaxed text-muted-foreground">
            {article.excerpt}
          </p>
        )}

        {/* Footer */}
        <div className="mt-auto flex flex-wrap items-center gap-x-4 gap-y-1 border-t border-border pt-3 text-xs text-muted-foreground">
          <span className="inline-flex items-center gap-1">
            <User className="h-3.5 w-3.5" />
            <span>Auteur</span>
          </span>

          {formattedDate && (
            <span className="inline-flex items-center gap-1">
              <Calendar className="h-3.5 w-3.5" />
              <time dateTime={article.published_at!}>{formattedDate}</time>
            </span>
          )}

          {article.reading_time_minutes != null && (
            <span className="inline-flex items-center gap-1">
              <Clock className="h-3.5 w-3.5" />
              <span>{article.reading_time_minutes} min</span>
            </span>
          )}
        </div>
      </div>
    </article>
  );
}
