import { Calendar, Clock, Tag, User } from "lucide-react";
import type { Article } from "../../types";

export interface BlogDetailProps {
  article: Article;
}

export function BlogDetail({ article }: BlogDetailProps) {
  const formattedDate = article.published_at
    ? new Date(article.published_at).toLocaleDateString("nl-NL", {
        year: "numeric",
        month: "long",
        day: "numeric",
      })
    : null;

  return (
    <article className="mx-auto max-w-3xl">
      {/* Title */}
      <h1 className="text-3xl font-bold leading-tight tracking-tight text-foreground sm:text-4xl lg:text-5xl">
        {article.title}
      </h1>

      {/* Meta */}
      <div className="mt-4 flex flex-wrap items-center gap-x-4 gap-y-2 text-sm text-muted-foreground">
        {article.category && (
          <span className="rounded-full bg-primary/10 px-3 py-0.5 text-xs font-medium text-primary">
            {article.category.name}
          </span>
        )}

        <span className="inline-flex items-center gap-1">
          <User className="h-4 w-4" />
          <span>Auteur</span>
        </span>

        {formattedDate && (
          <span className="inline-flex items-center gap-1">
            <Calendar className="h-4 w-4" />
            <time dateTime={article.published_at!}>{formattedDate}</time>
          </span>
        )}

        {article.reading_time_minutes != null && (
          <span className="inline-flex items-center gap-1">
            <Clock className="h-4 w-4" />
            <span>{article.reading_time_minutes} min leestijd</span>
          </span>
        )}
      </div>

      {/* Featured image */}
      {article.featured_image && (
        <div className="mt-8 overflow-hidden rounded-lg">
          <img
            src={article.featured_image}
            alt={article.title}
            className="h-auto w-full object-cover"
          />
        </div>
      )}

      {/* Content */}
      {article.content_html && (
        <div
          className="prose prose-lg mt-8 max-w-none text-foreground prose-headings:text-foreground prose-a:text-primary prose-strong:text-foreground prose-code:text-foreground prose-pre:bg-muted prose-pre:text-foreground prose-blockquote:border-primary prose-blockquote:text-muted-foreground"
          dangerouslySetInnerHTML={{ __html: article.content_html }}
        />
      )}

      {/* Tags */}
      {article.tags && article.tags.length > 0 && (
        <div className="mt-10 border-t border-border pt-6">
          <div className="flex items-center gap-2">
            <Tag className="h-4 w-4 text-muted-foreground" />
            <span className="text-sm font-medium text-muted-foreground">Tags:</span>
          </div>
          <div className="mt-3 flex flex-wrap gap-2">
            {article.tags.map((tag) => (
              <span
                key={tag.id}
                className="rounded-full border border-border bg-muted px-3 py-1 text-xs font-medium text-muted-foreground transition-colors hover:bg-primary/10 hover:text-primary"
              >
                {tag.name}
              </span>
            ))}
          </div>
        </div>
      )}
    </article>
  );
}
