"use client";

import { ChevronLeft, ChevronRight } from "lucide-react";
import type { Article } from "../../types";
import { BlogCard } from "./blog-card";

export interface BlogGridProps {
  articles: Article[];
  basePath?: string;
  loading?: boolean;
  page?: number;
  totalPages?: number;
  onPageChange?: (page: number) => void;
}

function SkeletonCard() {
  return (
    <div className="flex flex-col overflow-hidden rounded-lg border border-border bg-secondary shadow-sm">
      <div className="aspect-[16/9] animate-pulse bg-muted" />
      <div className="flex flex-1 flex-col p-4 sm:p-5">
        <div className="mb-2 h-5 w-3/4 animate-pulse rounded bg-muted" />
        <div className="mb-1 h-4 w-full animate-pulse rounded bg-muted" />
        <div className="mb-4 h-4 w-2/3 animate-pulse rounded bg-muted" />
        <div className="mt-auto border-t border-border pt-3">
          <div className="h-3 w-1/2 animate-pulse rounded bg-muted" />
        </div>
      </div>
    </div>
  );
}

export function BlogGrid({
  articles,
  basePath = "/blog",
  loading = false,
  page = 1,
  totalPages = 1,
  onPageChange,
}: BlogGridProps) {
  if (loading) {
    return (
      <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
        {Array.from({ length: 6 }).map((_, i) => (
          <SkeletonCard key={i} />
        ))}
      </div>
    );
  }

  if (articles.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center rounded-lg border border-border bg-muted/50 px-6 py-16 text-center">
        <p className="text-lg font-medium text-foreground">
          Nog geen artikelen gepubliceerd
        </p>
        <p className="mt-1 text-sm text-muted-foreground">
          Kom later terug voor nieuwe content.
        </p>
      </div>
    );
  }

  return (
    <div>
      <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
        {articles.map((article) => (
          <BlogCard key={article.id} article={article} basePath={basePath} />
        ))}
      </div>

      {/* Pagination */}
      {totalPages > 1 && onPageChange && (
        <nav
          aria-label="Paginering"
          className="mt-8 flex items-center justify-center gap-2"
        >
          <button
            type="button"
            onClick={() => onPageChange(page - 1)}
            disabled={page <= 1}
            className="inline-flex items-center gap-1 rounded-md border border-border bg-secondary px-3 py-2 text-sm font-medium text-foreground transition-colors hover:bg-muted disabled:pointer-events-none disabled:opacity-50"
          >
            <ChevronLeft className="h-4 w-4" />
            Vorige
          </button>

          <span className="px-3 text-sm text-muted-foreground">
            Pagina {page} van {totalPages}
          </span>

          <button
            type="button"
            onClick={() => onPageChange(page + 1)}
            disabled={page >= totalPages}
            className="inline-flex items-center gap-1 rounded-md border border-border bg-secondary px-3 py-2 text-sm font-medium text-foreground transition-colors hover:bg-muted disabled:pointer-events-none disabled:opacity-50"
          >
            Volgende
            <ChevronRight className="h-4 w-4" />
          </button>
        </nav>
      )}
    </div>
  );
}
